package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors;
import com.google.protobuf.ExtensionRegistry;
import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class AnnotationsTest {

  private ExtensionRegistryLite mockRegistryLite;
  private ExtensionRegistry mockRegistry;

  @BeforeEach
  void setUp() {
    mockRegistryLite = mock(ExtensionRegistryLite.class);
    mockRegistry = mock(ExtensionRegistry.class);
  }

  @Test
  void testRegisterAllExtensions_ExtensionRegistryLite() throws Exception {
    Method method = Annotations.class.getMethod("registerAllExtensions", ExtensionRegistryLite.class);
    assertDoesNotThrow(() -> {
      try {
        method.invoke(null, mockRegistryLite);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
  }

  @Test
  void testRegisterAllExtensions_ExtensionRegistry() throws Exception {
    Method method = Annotations.class.getMethod("registerAllExtensions", ExtensionRegistry.class);
    assertDoesNotThrow(() -> {
      try {
        method.invoke(null, mockRegistry);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
  }

  @Test
  void testGetDescriptor_notNull() throws Exception {
    Method method = Annotations.class.getMethod("getDescriptor");
    Object result = method.invoke(null);
    assertNotNull(result);
    assertTrue(result instanceof Descriptors.FileDescriptor);
  }

  @Test
  void testConstants() throws Exception {
    assertEquals(92066888, Annotations.SERIALIZED_NAME_FIELD_NUMBER);
    assertEquals(92066888, Annotations.SERIALIZED_VALUE_FIELD_NUMBER);
    assertNotNull(Annotations.serializedName);
    assertNotNull(Annotations.serializedValue);
  }

  @Test
  void testPrivateConstructor() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
    var constructor = Annotations.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    Object instance = constructor.newInstance();
    assertNotNull(instance);
    assertTrue(instance instanceof Annotations);
  }
}
